'use client';

import React from 'react';
import { Button } from '@/components/ui/button';
import { useWalletStore } from '@/lib/store/use-wallet-store';
import {
    IconWallet,
    IconLoader2,
    IconCheck,
    IconChevronDown,
    IconCircleFilled,
    IconArrowRight
} from '@tabler/icons-react';
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuLabel,
    DropdownMenuSeparator,
    DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import { cn } from '@/lib/utils';

export function WalletConnect() {
    const { address, network, isConnected, isConnecting, connect, disconnect } = useWalletStore();

    const truncatedAddress = address
        ? `${address.slice(0, 6)}...${address.slice(-4)}`
        : '';

    if (!isConnected) {
        return (
            <Button
                onClick={connect}
                disabled={isConnecting}
                variant="default"
                className="relative overflow-hidden group px-6 bg-primary hover:bg-primary/90 text-primary-foreground shadow-lg transition-all duration-300 hover:scale-[1.02]"
            >
                {isConnecting ? (
                    <>
                        <IconLoader2 className="mr-2 h-4 w-4 animate-spin" />
                        Connecting...
                    </>
                ) : (
                    <>
                        <IconWallet className="mr-2 h-4 w-4 transition-transform group-hover:rotate-12" />
                        Connect Wallet
                    </>
                )}
            </Button>
        );
    }

    return (
        <div className="flex items-center gap-2">
            {/* Network Badge */}
            <div className="hidden md:flex items-center gap-1.5 px-3 py-1.5 rounded-full bg-secondary/50 border border-border text-[11px] font-medium tracking-tight">
                <IconCircleFilled className="h-2 w-2 text-emerald-500 animate-pulse" />
                <span className="text-muted-foreground uppercase">{network}</span>
            </div>

            <DropdownMenu>
                <DropdownMenuTrigger asChild>
                    <Button
                        variant="outline"
                        className="group border-primary/20 bg-background hover:bg-accent/50 transition-all duration-200 pl-3 pr-2"
                    >
                        <div className="flex items-center gap-2">
                            <div className="h-6 w-6 rounded-full bg-primary/10 flex items-center justify-center border border-primary/20">
                                <IconCheck className="h-3 w-3 text-primary" />
                            </div>
                            <span className="font-mono text-sm leading-none">{truncatedAddress}</span>
                            <IconChevronDown className="h-4 w-4 text-muted-foreground transition-transform group-data-[state=open]:rotate-180" />
                        </div>
                    </Button>
                </DropdownMenuTrigger>
                <DropdownMenuContent align="end" className="w-56 mt-2">
                    <DropdownMenuLabel className="font-normal p-4">
                        <div className="flex flex-col space-y-2">
                            <p className="text-xs font-medium text-muted-foreground uppercase tracking-widest leading-none">Connected Wallet</p>
                            <p className="text-sm font-mono break-all leading-relaxed">{address}</p>
                        </div>
                    </DropdownMenuLabel>
                    <DropdownMenuSeparator />
                    <DropdownMenuItem className="p-3 cursor-pointer group">
                        <div className="flex items-center gap-3 w-full">
                            <div className="p-2 rounded-lg bg-emerald-500/10 text-emerald-600">
                                <IconCheck size={18} />
                            </div>
                            <div className="flex flex-col">
                                <span className="text-sm font-medium">Sepolia Network</span>
                                <span className="text-[10px] text-muted-foreground font-mono">ID: 11155111</span>
                            </div>
                        </div>
                    </DropdownMenuItem>
                    <DropdownMenuSeparator />
                    <DropdownMenuItem
                        onClick={disconnect}
                        className="p-3 cursor-pointer text-destructive focus:bg-destructive/10 focus:text-destructive group"
                    >
                        <div className="flex items-center justify-between w-full">
                            <div className="flex items-center gap-3">
                                <IconWallet size={18} />
                                <span className="text-sm font-medium">Disconnect</span>
                            </div>
                            <IconArrowRight size={14} className="opacity-0 -translate-x-2 transition-all group-hover:opacity-100 group-hover:translate-x-0" />
                        </div>
                    </DropdownMenuItem>
                </DropdownMenuContent>
            </DropdownMenu>
        </div>
    );
}
